// Bind the tuple components of both candidate results to named locals. Each
// pattern-match `let (sent_packets, ack) = rX` inside the synthetic
// implication's ensures introduces a *fresh* binding scoped to that
// conjunct; rebinding once at the top lets z3 see `sent_packetsK@` and
// `ackK@@` as shared syntactic handles across the pair of runs (K = 1, 2).
let (sent_packets1, ack1) = r1;
let (sent_packets2, ack2) = r2;

// Materialize the abstract-set form of each run's sent-packet sequence as a
// named ghost local. The 4th argument of `receive_packet` is the result of
// applying `abstractify_seq_of_cpackets_to_set_of_sht_packets` to
// `sent_packetsK@`; named handles `abs_sentK` give z3 a uniform sub-term
// to use in trigger patterns over both runs and keep the `receive_packet`
// applications syntactically identical except for their `K`-indexed args.
let abs_sent1: Set<Packet> =
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets1@);
let abs_sent2: Set<Packet> =
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets2@);

// Tautological `X ==> X` asserts that mention each ensures-conjunct's head
// term side-by-side for run 1 and run 2. Each `X ==> X` is a propositional
// tautology (so the asserts cannot introduce unsoundness — Verus will accept
// them under any context), but writing them in this position registers both
// head terms in the same SMT scope, so z3's matching loop can fire the two
// runs' ensures-quantifier triggers symmetrically.

// outbound_packet_seq_is_valid is the first conjunct of each run's ensures
// and itself a `forall|i|` over its argument; registering both head terms
// gives z3 a place to align the two foralls' triggers.
assert(outbound_packet_seq_is_valid(sent_packets1@)
    ==> outbound_packet_seq_is_valid(sent_packets1@));
assert(outbound_packet_seq_is_valid(sent_packets2@)
    ==> outbound_packet_seq_is_valid(sent_packets2@));

// receive_packet is the second conjunct of each run's ensures. Its body is
// `pub open spec(checked) fn`, so the head term unfolds once z3 has it in
// scope; planting both runs' head terms at top level lets the matching loop
// case-split on the disjunction inside `receive_packet` symmetrically.
assert(receive_packet(pre_self_@, post1_self_@, cpacket@, abs_sent1, ack1@@)
    ==> receive_packet(pre_self_@, post1_self_@, cpacket@, abs_sent1, ack1@@));
assert(receive_packet(pre_self_@, post2_self_@, cpacket@, abs_sent2, ack2@@)
    ==> receive_packet(pre_self_@, post2_self_@, cpacket@, abs_sent2, ack2@@));

// host_state_common_postconditions is the third conjunct of each run's
// ensures. It was already `reveal`-ed by the schema scaffolding at the top
// of the body; planting both runs' head terms here ensures z3 sees a uniform
// trigger pattern `postK_self_.host_state_common_postconditions(pre_self_,
// cpacket, sent_packetsK@)` across the two runs.
assert(post1_self_.host_state_common_postconditions(pre_self_, cpacket, sent_packets1@)
    ==> post1_self_.host_state_common_postconditions(pre_self_, cpacket, sent_packets1@));
assert(post2_self_.host_state_common_postconditions(pre_self_, cpacket, sent_packets2@)
    ==> post2_self_.host_state_common_postconditions(pre_self_, cpacket, sent_packets2@));
